 1→// Package posthog provides PostHog analytics integration for the API server.
 2→// When POSTHOG_API_KEY is absent, all functions return no-op values.
 3→package posthog
 4→
 5→import (
 6→	"context"
 7→	"log/slog"
 8→
 9→	ph "github.com/posthog/posthog-go"
10→)
11→
12→// Client wraps a posthog.Client with graceful no-op behavior.
13→type Client struct {
14→	inner ph.Client
15→}
16→
17→// New creates a PostHog client. Returns a no-op client if apiKey is empty.
18→func New(apiKey, host string) (*Client, error) {
19→	if apiKey == "" {
20→		slog.Info("posthog: disabled (POSTHOG_API_KEY not set)")
21→		return &Client{}, nil
22→	}
23→
24→	endpoint := host
25→	if endpoint == "" {
26→		endpoint = ph.DefaultEndpoint
27→	}
28→
29→	inner, err := ph.NewWithConfig(apiKey, ph.Config{
30→		Endpoint: endpoint,
31→	})
32→	if err != nil {
33→		return nil, err
34→	}
35→
36→	slog.Info("posthog: initialized", "endpoint", endpoint)
37→	return &Client{inner: inner}, nil
38→}
39→
40→// Enabled reports whether PostHog is active.
41→func (c *Client) Enabled() bool {
42→	return c.inner != nil
43→}
44→
45→// Inner returns the underlying posthog.Client for direct use, or nil if disabled.
46→func (c *Client) Inner() ph.Client {
47→	return c.inner
48→}
49→
50→// WrapSlogHandler wraps a slog.Handler with PostHog exception capture.
51→// Returns the handler unchanged if PostHog is disabled.
52→func (c *Client) WrapSlogHandler(h slog.Handler) slog.Handler {
53→	if c.inner == nil {
54→		return h
55→	}
56→	return ph.NewSlogCaptureHandler(h, c.inner,
57→		ph.WithDistinctIDFn(func(_ context.Context, _ slog.Record) string {
58→			return "kapow-api"
59→		}),
60→	)
61→}
62→
63→// Close flushes pending events and shuts down the client.
64→func (c *Client) Close() error {
65→	if c.inner == nil {
66→		return nil
67→	}
68→	return c.inner.Close()
69→}
